1	package com.interview.lld.ratelimiter.service;
2	
3	import java.util.concurrent.ConcurrentHashMap;
4	
5	import com.interview.lld.ratelimiter.gateway.Clock;
6	import com.interview.lld.ratelimiter.model.CustomerBucket;
7	import com.interview.lld.ratelimiter.model.RateLimitPolicy;
8	import com.interview.lld.ratelimiter.model.UnknownCustomerException;
9	import com.interview.lld.ratelimiter.strategy.RateLimitStrategy;
10	import com.interview.lld.ratelimiter.strategy.StrategyFactory;
11	
12	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
13	// The brain. It owns the map of customer -> their bucket, the shared policy, the
14	// injected clock, and the factory that builds a strategy per customer. Its one
15	// public job is to answer allow(customerId, nowNanos): true means "let this
16	// request through", false means "rate limited". This base version is written
17	// CLEAN and single-threaded-correct — it has NO locking around the strategy call.
18	// The thread-safe version is a subclass that overrides two tiny hook methods.
19	// 🎙️ "The service is the brain. It keeps a map from customer to that customer's
20	//      bucket, and answers one question — allow this request, yes or no. I keep
21	//      this base version lock-free so the design reads cleanly, then add safety in
22	//      a subclass that overrides one pair of hook methods."
23	public class RateLimiterService {
24	
25	    private final Clock clock;
26	    private final RateLimitPolicy policy;
27	    private final StrategyFactory strategyFactory;
28	    private final boolean autoRegister;
29	
30	    // WHY: ConcurrentHashMap so registering a brand-new customer is itself
31	    //      thread-safe (computeIfAbsent is atomic for the map structure). The
32	    //      per-customer DECISION is guarded separately by the customer's own lock
33	    //      in the thread-safe subclass — that is the lock striping.
34	    // WHY: this lives even in the base class because the map is the registry the
35	    //      orchestrator owns — the single place that can enumerate every customer.
36	    private final ConcurrentHashMap<String, CustomerBucket> buckets = new ConcurrentHashMap<>();
37	
38	    public RateLimiterService(Clock clock,
39	                              RateLimitPolicy policy,
40	                              StrategyFactory strategyFactory,
41	                              boolean autoRegister) {
42	        this.clock = clock;
43	        this.policy = policy;
44	        this.strategyFactory = strategyFactory;
45	        this.autoRegister = autoRegister;
46	    }
47	
48	    // WHY: explicit registration up front. Some deployments know their customers
49	    //      ahead of time and want an unknown id rejected as a typo rather than
50	    //      auto-onboarded. Returns the bucket so a caller could pre-warm it.
51	    public void register(String customerId) {
52	        buckets.computeIfAbsent(customerId, id -> newBucket());
53	    }
54	
55	    // ── THE ONE PUBLIC OPERATION ────────────────────────────────────────────
56	    // Returns true if the request is allowed, false if it is rate-limited.
57	    public boolean allow(String customerId) {
58	        CustomerBucket bucket = resolveBucket(customerId);
59	
60	        // WHY: read the clock ONCE, right here, and pass it down. Both refill math
61	        //      and window eviction then use one consistent "now", and the strategy
62	        //      stays a pure function of the time we hand it.
63	        long now = clock.nowNanos();
64	
65	        // WHY: the read-modify-write on the strategy is wrapped in the gate hooks.
66	        //      In THIS base class the hooks do nothing, so the body runs plainly.
67	        //      In the thread-safe subclass the hooks lock/unlock this customer's
68	        //      lock, turning the body into one atomic step.
69	        acquireGate(bucket);
70	        try {
71	            RateLimitStrategy strategy = bucket.strategy();
72	            return strategy.tryAcquire(now);
73	        } finally {
74	            releaseGate(bucket);
75	        }
76	    }
77	
78	    // ── TEMPLATE METHOD HOOKS ────────────────────────────────────────────────
79	    // WHY: these do NOTHING here. The clean base has zero lock code. The
80	    //      thread-safe subclass overrides exactly these two to lock and unlock the
81	    //      customer's own lock — the entire concurrency change is ~6 lines there.
82	    // 🎙️ "These two hooks are empty in the clean version. The thread-safe subclass
83	    //      overrides only them to lock the per-customer lock. The diff between safe
84	    //      and unsafe is one tiny pair of methods."
85	    protected void acquireGate(CustomerBucket bucket) {
86	        // no-op in the clean single-threaded core
87	    }
88	
89	    protected void releaseGate(CustomerBucket bucket) {
90	        // no-op in the clean single-threaded core
91	    }
92	
93	    // WHY: every customer that is allowed to make requests must reach a defined
94	    //      outcome. If auto-register is on, an unseen id lazily gets a fresh
95	    //      bucket; if off, we reject with a typed error rather than silently
96	    //      granting unlimited access.
97	    protected CustomerBucket resolveBucket(String customerId) {
98	        if (autoRegister) {
99	            return buckets.computeIfAbsent(customerId, id -> newBucket());
100	        }
101	        CustomerBucket existing = buckets.get(customerId);
102	
103	        if (existing == null) {
104	            throw new UnknownCustomerException(customerId);
105	        }
106	        return existing;
107	    }
108	
109	    // WHY: a fresh strategy per bucket so each customer carries independent state.
110	    //      The strategy is built through the factory so the service never names a
111	    //      concrete algorithm class.
112	    private CustomerBucket newBucket() {
113	        RateLimitStrategy strategy = strategyFactory.create(policy, clock.nowNanos());
114	        return new CustomerBucket(strategy);
115	    }
116	
117	    // WHY: expose the live customer count so a test (or an admin endpoint) can see
118	    //      how many distinct customers the limiter is tracking.
119	    public int trackedCustomerCount() {
120	        return buckets.size();
121	    }
122	}
