3	import com.interview.lld.ratelimiter.gateway.Clock;
4	import com.interview.lld.ratelimiter.model.CustomerBucket;
5	import com.interview.lld.ratelimiter.model.RateLimitPolicy;
6	import com.interview.lld.ratelimiter.strategy.StrategyFactory;
7	
8	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
9	// The thread-safe version. It reuses ALL of the base service unchanged and
10	// overrides only the two empty gate hooks. acquireGate locks the customer's OWN
11	// lock; releaseGate unlocks it. Because each customer has a separate lock (lock
12	// striping), customer A and customer B run fully in parallel — they never touch
13	// the same lock. Only two requests from the SAME customer serialize, and they
14	// must, because they share one token count.
15	// 🎙️ "The thread-safe service is a six-line subclass. It overrides the two hooks
16	//      to lock and unlock that customer's own lock. Lock striping: every customer
17	//      has their own lock, so different customers never block each other. That is
18	//      exactly the requirement — one noisy customer cannot slow everyone down."
19	public final class ThreadSafeRateLimiterService extends RateLimiterService {
20	
21	    public ThreadSafeRateLimiterService(Clock clock,
22	                                        RateLimitPolicy policy,
23	                                        StrategyFactory strategyFactory,
24	                                        boolean autoRegister) {
25	        super(clock, policy, strategyFactory, autoRegister);
26	    }
27	
28	    // WHY: lock THIS customer's own lock. Two threads for the same customer race
29	    //      to acquire it — one wins and does the check-and-spend atomically, the
30	    //      other waits and then sees the updated token count. Different customers
31	    //      hold different locks, so they never wait on each other.
32	    // WHY: ReentrantLock (the lock type on CustomerBucket) so the same thread can
33	    //      re-enter if a guarded path ever calls another guarded path.
34	    @Override
35	    protected void acquireGate(CustomerBucket bucket) {
36	        bucket.lock().lock();
37	    }
38	
39	    // WHY: always release in the service's finally block (see base.allow), so the
40	    //      lock is freed even if the strategy throws.
41	    @Override
42	    protected void releaseGate(CustomerBucket bucket) {
43	        bucket.lock().unlock();
44	    }
45	}
