2	
3	import java.util.ArrayDeque;
4	import java.util.Deque;
5	
6	import com.interview.lld.ratelimiter.model.RateLimitPolicy;
7	
8	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
9	// Sliding-window log. We keep the timestamp of every allowed request in a queue.
10	// On each new request we first throw away every timestamp older than one window,
11	// then ask: are there still fewer than `capacity` left? If yes, allow and record
12	// this request's timestamp. Unlike a fixed window, this never allows a double
13	// burst at a window boundary — the window slides continuously with "now".
14	// 🎙️ "Sliding window keeps the actual timestamps of recent allowed requests. On
15	//      each call I drop anything older than the window, then check if the count
16	//      is still under the limit. It is smoother than token bucket — no boundary
17	//      burst — at the cost of storing the recent timestamps."
18	//
19	// NOT thread-safe by itself — the service calls this only while holding that
20	// customer's lock, so the deque is never touched by two threads at once.
21	public final class SlidingWindowLogStrategy implements RateLimitStrategy {
22	
23	    private final long capacity;
24	    private final long windowNanos;
25	
26	    // WHY: a deque of timestamps, oldest at the head. We only ever drop from the
27	    //      head (expired ones) and add to the tail (newest) — both O(1).
28	    private final Deque<Long> timestamps = new ArrayDeque<>();
29	
30	    public SlidingWindowLogStrategy(RateLimitPolicy policy) {
31	        this.capacity = policy.capacity();
32	        this.windowNanos = policy.windowNanos();
33	    }
34	
35	    @Override
36	    public boolean tryAcquire(long nowNanos) {
37	        evictOld(nowNanos);
38	
39	        if (timestamps.size() < capacity) {
40	            // WHY: record this request's time so it counts against the limit until
41	            //      it slides out of the window one window-length from now.
42	            timestamps.addLast(nowNanos);
43	            return true;
44	        }
45	        return false;
46	    }
47	
48	    // WHY: drop every timestamp that is now older than the window. The boundary
49	    //      is "now - window": anything at or before that no longer counts.
50	    private void evictOld(long nowNanos) {
51	        long cutoff = nowNanos - windowNanos;
52	
53	        while (!timestamps.isEmpty() && timestamps.peekFirst() <= cutoff) {
