3	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
4	// The real production clock. It reads the machine's monotonic timer. We use a
5	// monotonic source (nanoTime) rather than wall-clock time so that an NTP
6	// adjustment or a clock going backwards can never make the limiter think time
7	// flowed in reverse and hand out free tokens.
8	// 🎙️ "The real clock just reads nanoTime — a monotonic timer that only ever
9	//      moves forward, so a clock correction can never give a customer free
10	//      requests."
11	public final class SystemClock implements Clock {
12	
13	    @Override
14	    public long nowNanos() {
15	        // WHY: nanoTime is monotonic. currentTimeMillis can jump backwards when
16	        //      the OS syncs its clock — that would corrupt refill math.
17	        return System.nanoTime();
18	    }
19	}
