3	import java.util.concurrent.CyclicBarrier;
4	import java.util.concurrent.ExecutorService;
5	import java.util.concurrent.Executors;
6	import java.util.concurrent.TimeUnit;
7	import java.util.concurrent.atomic.AtomicInteger;
8	
9	import com.interview.lld.ratelimiter.gateway.FakeClock;
10	import com.interview.lld.ratelimiter.model.RateLimitPolicy;
11	import com.interview.lld.ratelimiter.model.UnknownCustomerException;
12	import com.interview.lld.ratelimiter.service.RateLimiterService;
13	import com.interview.lld.ratelimiter.service.ThreadSafeRateLimiterService;
14	import com.interview.lld.ratelimiter.strategy.StrategyFactory;
15	import com.interview.lld.ratelimiter.strategy.StrategyType;
16	
17	// Java 17+
18	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
19	// A human-readable demo. Each case prints "Case N ... -> OK" so a green run is
20	// obvious at a glance. It exercises the tricky paths: capacity exhaustion, refill
21	// after time passes, the sliding window boundary, an unknown-customer rejection,
22	// per-customer isolation, and a concurrent burst on ONE customer hitting exactly
23	// the limit.
24	public final class Main {
25	
26	    private static final long ONE_SECOND = 1_000_000_000L;
27	
28	    public static void main(String[] args) throws Exception {
29	        case1TokenBucketBurstThenDeny();
30	        case2RefillAfterTime();
31	        case3SlidingWindowNoBoundaryBurst();
32	        case4UnknownCustomerRejected();
33	        case5DifferentCustomersIsolated();
34	        case6ConcurrentBurstOnOneCustomer();
35	        System.out.println("ALL CASES PASSED");
36	    }
37	
38	    // Case 1: token bucket lets the full burst through, then denies.
39	    private static void case1TokenBucketBurstThenDeny() {
40	        FakeClock clock = new FakeClock(0);
41	        RateLimiterService limiter = new ThreadSafeRateLimiterService(
42	                clock, RateLimitPolicy.perSecond(5),
43	                new StrategyFactory(StrategyType.TOKEN_BUCKET), true);
44	
45	        int allowed = 0;
46	        for (int i = 0; i < 8; i++) {
47	            if (limiter.allow("alice")) {
48	                allowed++;
49	            }
50	        }
51	        assertTrue(allowed == 5, "expected 5 allowed in burst, got " + allowed);
52	        System.out.println("Case 1 token bucket: 5 allowed then denied -> OK");
53	    }
54	
55	    // Case 2: after one full second, the bucket has refilled.
56	    private static void case2RefillAfterTime() {
57	        FakeClock clock = new FakeClock(0);
58	        RateLimiterService limiter = new ThreadSafeRateLimiterService(
59	                clock, RateLimitPolicy.perSecond(2),
60	                new StrategyFactory(StrategyType.TOKEN_BUCKET), true);
61	
62	        assertTrue(limiter.allow("bob"), "1st should pass");
63	        assertTrue(limiter.allow("bob"), "2nd should pass");
64	        assertTrue(!limiter.allow("bob"), "3rd should be denied (bucket empty)");
65	
66	        // WHY: move the fake clock forward one second — no Thread.sleep needed.
67	        clock.advanceNanos(ONE_SECOND);
68	        assertTrue(limiter.allow("bob"), "after 1s the bucket refilled");
69	        System.out.println("Case 2 refill after 1s -> OK");
70	    }
71	
72	    // Case 3: sliding window does not allow a double burst across a boundary.
73	    private static void case3SlidingWindowNoBoundaryBurst() {
74	        FakeClock clock = new FakeClock(0);
75	        RateLimiterService limiter = new ThreadSafeRateLimiterService(
76	                clock, RateLimitPolicy.perSecond(3),
77	                new StrategyFactory(StrategyType.SLIDING_WINDOW), true);
78	
79	        for (int i = 0; i < 3; i++) {
80	            assertTrue(limiter.allow("carol"), "first 3 pass");
81	        }
82	        assertTrue(!limiter.allow("carol"), "4th denied within window");
83	
84	        // Move forward half a window — still denied, window slid only halfway.
85	        clock.advanceNanos(ONE_SECOND / 2);
86	        assertTrue(!limiter.allow("carol"), "still denied mid-window");
87	
88	        // Now move past the original window so the first 3 expire.
89	        clock.advanceNanos(ONE_SECOND);
90	        assertTrue(limiter.allow("carol"), "old requests slid out, allowed again");
91	        System.out.println("Case 3 sliding window no boundary burst -> OK");
92	    }
93	
94	    // Case 4: in strict mode an unknown customer is rejected with a typed error.
95	    private static void case4UnknownCustomerRejected() {
96	        FakeClock clock = new FakeClock(0);
97	        RateLimiterService limiter = new ThreadSafeRateLimiterService(
98	                clock, RateLimitPolicy.perSecond(5),
99	                new StrategyFactory(StrategyType.TOKEN_BUCKET), false);
100	
101	        boolean threw = false;
102	        try {
103	            limiter.allow("ghost");
104	        } catch (UnknownCustomerException e) {
105	            threw = true;
106	        }
107	        assertTrue(threw, "unknown customer must be rejected in strict mode");
108	        System.out.println("Case 4 unknown customer rejected -> OK");
109	    }
110	
111	    // Case 5: one customer exhausting their limit does not affect another.
112	    private static void case5DifferentCustomersIsolated() {
113	        FakeClock clock = new FakeClock(0);
114	        RateLimiterService limiter = new ThreadSafeRateLimiterService(
115	                clock, RateLimitPolicy.perSecond(2),
116	                new StrategyFactory(StrategyType.TOKEN_BUCKET), true);
117	
118	        assertTrue(limiter.allow("x"), "x 1st");
119	        assertTrue(limiter.allow("x"), "x 2nd");
120	        assertTrue(!limiter.allow("x"), "x exhausted");
121	
122	        // y is untouched by x's exhaustion.
123	        assertTrue(limiter.allow("y"), "y 1st unaffected");
124	        assertTrue(limiter.allow("y"), "y 2nd unaffected");
125	        System.out.println("Case 5 customers isolated -> OK");
126	    }
127	
128	    // Case 6: 50 threads hammer ONE customer at the boundary; exactly the limit
129	    // is allowed and no more.
130	    private static void case6ConcurrentBurstOnOneCustomer() throws Exception {
131	        int threads = 50;
132	        long limit = 10;
133	        FakeClock clock = new FakeClock(0);
134	        RateLimiterService limiter = new ThreadSafeRateLimiterService(
135	                clock, RateLimitPolicy.perSecond(limit),
136	                new StrategyFactory(StrategyType.TOKEN_BUCKET), true);
137	        limiter.register("hot");
138	
139	        CyclicBarrier barrier = new CyclicBarrier(threads);
140	        AtomicInteger allowed = new AtomicInteger(0);
141	        ExecutorService pool = Executors.newFixedThreadPool(threads);
142	
143	        for (int i = 0; i < threads; i++) {
144	            pool.submit(() -> {
145	                try {
146	                    barrier.await();
147	                    if (limiter.allow("hot")) {
148	                        allowed.incrementAndGet();
149	                    }
150	                } catch (Exception e) {
151	                    throw new RuntimeException(e);
152	                }
153	            });
154	        }
155	        pool.shutdown();
156	        assertTrue(pool.awaitTermination(10, TimeUnit.SECONDS), "threads finished");
157	
158	        assertTrue(allowed.get() == limit,
159	                "exactly " + limit + " allowed at boundary, got " + allowed.get());
160	        System.out.println("Case 6 concurrent burst: exactly " + limit
161	                + " allowed under 50-thread race -> OK");
162	    }
163	
164	    // WHY: a tiny assert helper so the driver fails LOUD at the exact line, not a
165	    //      silent wrong answer.
166	    private static void assertTrue(boolean cond, String message) {
167	        if (!cond) {
168	            throw new AssertionError(message);
169	        }
170	    }
171	}
